class TestProofState(unittest.TestCase):
    """测试证明状态"""

    def setUp(self):
        self.state = SimpleProofState()

    def test_add_predicate(self):
        """测试添加谓词"""
        result = self.state.add("coll a b c")
        self.assertTrue(result)
        self.assertEqual(len(self.state.predicates), 1)

    def test_add_duplicate(self):
        """测试添加重复谓词"""
        self.state.add("coll a b c")
        result = self.state.add("coll a b c")
        self.assertFalse(result)
        self.assertEqual(len(self.state.predicates), 1)

    def test_normalize_coll(self):
        """测试coll谓词规范化"""
        self.state.add("coll a b c")
        self.assertTrue(self.state.contains("coll b a c"))
        self.assertTrue(self.state.contains("coll c b a"))

    def test_normalize_para(self):
        """测试para谓词规范化"""
        self.state.add("para a b c d")
        self.assertTrue(self.state.contains("para a b c d"))


class TestDeductiveEngine(unittest.TestCase):
    """测试演绎引擎"""

    def setUp(self):
        self.engine = SimpleDeductiveEngine()

    def test_deduce_from_coll(self):
        """测试从共线推导"""
        self.engine.reset()
        self.engine.add_premise("coll a b c")
        self.engine.add_premise("coll a b d")

        steps = self.engine.deduce(max_steps=5)

        conclusions = [s.conclusion for s in steps]
        self.assertIn("coll a c d", conclusions)

    def test_deduce_from_para(self):
        """测试从平行推导"""
        self.engine.reset()
        self.engine.add_premise("para a b c d")
        self.engine.add_premise("para c d e f")

        steps = self.engine.deduce(max_steps=5)

        conclusions = [s.conclusion for s in steps]
        self.assertIn("para a b e f", conclusions)

    def test_deduce_from_cong(self):
        """测试从全等推导"""
        self.engine.reset()
        self.engine.add_premise("cong a b c d")
        self.engine.add_premise("cong c d e f")

        steps = self.engine.deduce(max_steps=5)

        conclusions = [s.conclusion for s in steps]
        self.assertIn("cong a b e f", conclusions)


