class TestTrainingDataGenerator(unittest.TestCase):
    """测试训练数据生成器"""

    def setUp(self):
        self.generator = TrainingDataGenerator()

    def test_parse_problem(self):
        """测试问题解析"""
        constructions, goal, predicates = self.generator.parse_problem(
            "a b c = triangle ? ncoll a b c"
        )
        self.assertEqual(len(constructions), 1)
        self.assertEqual(goal, "ncoll a b c")

    def test_generate_proof_data(self):
        """测试证明数据生成"""
        proof_data = self.generator.generate_proof_data(
            "a b c = triangle; m = midpoint m a b ? coll m a b", "test_problem"
        )

        self.assertEqual(proof_data.problem_name, "test_problem")
        self.assertTrue(len(proof_data.setup_predicates) > 0)
        self.assertTrue(len(proof_data.proof_steps) > 0)
        self.assertTrue(proof_data.is_solved)

    def test_generate_batch(self):
        """测试批量生成"""
        batch = self.generator.generate_batch(num_problems=5, include_random=False)
        self.assertGreaterEqual(len(batch), 0)

    def test_export_json(self):
        """测试JSON导出"""
        import tempfile

        proof_data = self.generator.generate_proof_data(
            "a b c = triangle; m = midpoint m a b ? coll m a b", "export_test"
        )

        with tempfile.NamedTemporaryFile(suffix=".json", delete=False, mode="w") as f:
            temp_path = f.name

        try:
            self.generator.export_to_file([proof_data], temp_path, output_format="json")

            with open(temp_path, "r", encoding="utf-8") as f:
                data = json.load(f)

            self.assertEqual(len(data), 1)
            self.assertEqual(data[0]["problem_name"], "export_test")
        finally:
            if os.path.exists(temp_path):
                os.unlink(temp_path)

    def test_get_training_sequences(self):
        """测试获取训练序列"""
        proof_data = self.generator.generate_proof_data(
            "a b c = triangle; m = midpoint m a b ? coll m a b", "seq_test"
        )

        sequences = self.generator.get_training_sequences([proof_data])

        self.assertEqual(len(sequences), 1)
        init, steps, goal = sequences[0]
        self.assertTrue(len(init) > 0)
        self.assertTrue(len(steps) > 0)


